import argparse
import json
import pickle
import numpy as np
import torch
import warnings
from torchvision import transforms, models
from PIL import Image
from pathlib import Path
from tqdm import tqdm
import timm
from transformers import AutoModel

warnings.filterwarnings('ignore')
Image.MAX_IMAGE_PIXELS = None

T_DINO = transforms.Compose([
    transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize([0.485,0.456,0.406],[0.229,0.224,0.225])
])
T_CLIP = transforms.Compose([
    transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize([0.48145466,0.4578275,0.40821073],[0.26862954,0.26130258,0.27577711])
])
T_RESNET = transforms.Compose([
    transforms.Resize(256, interpolation=transforms.InterpolationMode.BILINEAR),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize([0.485,0.456,0.406],[0.229,0.224,0.225])
])

class DS(torch.utils.data.Dataset):
    def __init__(self, txt, root, tfm):
        self.r = Path(root)
        self.t = tfm
        with open(txt) as f:
            self.s = [l.strip() for l in f if l.strip()]
    def __len__(self):
        return len(self.s)
    def __getitem__(self, i):
        return self.t(Image.open(self.r / self.s[i]).convert('RGB'))

@torch.no_grad()
def ext(model, loader, device, is_vit=False):
    model.eval()
    out = []
    for x in tqdm(loader, desc='feat'):
        x = x.to(device)
        y = model(x)
        if is_vit and hasattr(y, 'last_hidden_state'):
            y = y.last_hidden_state[:, 0]
        else:
            y = y.reshape(y.size(0), -1)
        z = model(torch.flip(x, dims=[3]))
        if is_vit and hasattr(z, 'last_hidden_state'):
            z = z.last_hidden_state[:, 0]
        else:
            z = z.reshape(z.size(0), -1)
        out.append(((y + z) * 0.5).cpu().numpy())
    return np.concatenate(out, axis=0)

def normalize(x):
    return x / (np.linalg.norm(x, axis=1, keepdims=True) + 1e-8)

def infer_dim(obj):
    if hasattr(obj, 'coef_'):
        return obj.coef_.shape[1]
    if isinstance(obj, np.ndarray):
        return obj.shape[-1]
    if isinstance(obj, list) and len(obj):
        return infer_dim(obj[0])
    if isinstance(obj, dict):
        if 'prototypes' in obj:
            return obj['prototypes'].shape[-1]
        if 'clfs' in obj:
            return infer_dim(obj['clfs'])
        if 'items' in obj and len(obj['items']):
            first = obj['items'][0]
            if isinstance(first, dict) and 'model' in first:
                return infer_dim(first['model'])
            return infer_dim(first)
    raise ValueError(f'Cannot infer dim from {type(obj)}')

def get_backbones(dim, device):
    if dim == 768:
        need = {'dinov2'}
    elif dim == 2048:
        need = {'resnet'}
    elif dim == 2816:
        need = {'dinov2', 'resnet'}
    elif dim == 3584:
        need = {'dinov2', 'resnet', 'clip'}
    else:
        raise ValueError(f'Unknown dim {dim}')
    backbones = {}
    if 'dinov2' in need:
        print('Loading DINOv2...')
        m = AutoModel.from_pretrained('facebook/dinov2-base')
        m.eval().to(device)
        backbones['dinov2'] = (m, True)
    if 'resnet' in need:
        print('Loading ResNet50...')
        m = models.resnet50(weights='IMAGENET1K_V2')
        m = torch.nn.Sequential(*list(m.children())[:-1])
        m.eval().to(device)
        backbones['resnet'] = (m, False)
    if 'clip' in need:
        print('Loading CLIP ViT...')
        m = timm.create_model('vit_base_patch16_clip_224.openai', pretrained=True, num_classes=0)
        m.eval().to(device)
        backbones['clip'] = (m, True)
    return backbones

def extract_all(dp, backbones, device):
    txt_path = dp / 'test.txt'
    img_root = dp / 'images'
    feats = {}
    for name, (model, is_vit) in backbones.items():
        if name == 'dinov2':
            tfm = T_DINO
        elif name == 'clip':
            tfm = T_CLIP
        else:
            tfm = T_RESNET
        ds = DS(txt_path, img_root, tfm)
        loader = torch.utils.data.DataLoader(ds, batch_size=64, shuffle=False, num_workers=4, pin_memory=True)
        f = ext(model, loader, device, is_vit=is_vit)
        feats[name] = normalize(f)
    return feats

def assemble(feats, dim):
    if dim == 768:
        return feats['dinov2']
    elif dim == 2048:
        return feats['resnet']
    elif dim == 2816:
        return np.concatenate([feats['dinov2'], feats['resnet']], axis=1)
    elif dim == 3584:
        return np.concatenate([feats['dinov2'], feats['resnet'], feats['clip']], axis=1)

def predict_proba(ck, X):
    if hasattr(ck, 'predict_proba'):
        return ck.predict_proba(X)
    if hasattr(ck, 'decision_function'):
        logits = ck.decision_function(X)
        e = np.exp(logits - np.max(logits, axis=1, keepdims=True))
        return e / np.sum(e, axis=1, keepdims=True)
    if isinstance(ck, np.ndarray):
        scores = np.zeros((len(X), ck.shape[1]))
        for d in range(ck.shape[0]):
            sim = X @ ck[d].T
            e = np.exp(sim - np.max(sim, axis=1, keepdims=True))
            scores += e / np.sum(e, axis=1, keepdims=True)
        return scores / ck.shape[0]
    if isinstance(ck, list):
        s = np.zeros((len(X), 10))
        for c in ck:
            s += predict_proba(c, X)
        return s / len(ck)
    if isinstance(ck, dict):
        if 'prototypes' in ck:
            return predict_proba(ck['prototypes'], X)
        if 'bias' in ck:
            clfs = ck.get('clfs', [])
            bias = ck.get('bias', np.zeros(10))
            logits = np.mean([c.decision_function(X) for c in clfs], axis=0) + bias
            e = np.exp(logits - np.max(logits, axis=1, keepdims=True))
            return e / np.sum(e, axis=1, keepdims=True)
        if 'items' in ck:
            total = None
            wsum = 0.0
            for item in ck['items']:
                if isinstance(item, dict) and 'weight' in item:
                    w = item['weight']
                    m = item.get('model', item)
                else:
                    w = 1.0
                    m = item
                p = predict_proba(m, X) * w
                total = p if total is None else total + p
                wsum += w
            return total / wsum if wsum > 0 else total
    raise ValueError(f'Unsupported checkpoint type {type(ck)}')

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()
    dp = Path(args.data_path)
    with open(args.checkpoint, 'rb') as f:
        ck = pickle.load(f)
    dim = infer_dim(ck)
    print(f'Inferred feature dim: {dim}')
    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    backbones = get_backbones(dim, device)
    feats = extract_all(dp, backbones, device)
    X = assemble(feats, dim)
    probs = predict_proba(ck, X)
    preds = np.argmax(probs, axis=1).tolist()
    with open(args.output, 'w') as f:
        json.dump({'predictions': preds}, f)
    print(f'Wrote {len(preds)} predictions to {args.output}')

if __name__ == '__main__':
    main()
